"use client";

/* ════════════════════════════════════════════════════════════════════════
   DriftChart — landed-cost index over time, per supplier.
   Ported from /Users/mac/Downloads/MAGELLAN UX/magellan-operations-room/05-suppliers.html
   Chart standard §8.8: true-pixel labels, focused supplier in solid line,
   others greyed; projection dashed; CM1 ceiling marker; breach pulse.
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useState } from "react";
import {
  SUP_SERIES,
  MONTHS_12,
  THREAT_INDEX,
  type SupSeries,
} from "@/features/ops/api/ops-suppliers-data";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export interface DriftChartProps {
  focusKey: string;
  /** Window in months (3, 6, 12) */
  win: number;
  /** Whether the side panel is open — crops history a bit when so */
  detailOpen: boolean;
  /** SVG height; we keep a fixed CSS height and a viewBox sized to width */
  height?: number;
}

const PAD = { L: 14, R: 14, T: 34, B: 42 };
const Y_MIN = 96;
const Y_MAX = 118;

export function DriftChart({ focusKey, win, detailOpen, height = 300 }: DriftChartProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 1000 });
  const reduced = usePrefersReducedMotion();
  const [hover, setHover] = useState<{ i: number; v: number; m: string; x: number; y: number } | null>(null);

  // Animated drift readout
  const focus = SUP_SERIES.find((s) => s.key === focusKey) ?? SUP_SERIES[0];
  const effWin = detailOpen ? Math.min(win, 8) : win;
  const off = 12 - effWin;
  const n = effWin;
  const slots = n + 2;
  const fv = focus.v.slice(off);
  const months = MONTHS_12.slice(off);
  const drift = fv[n - 1] - fv[0];

  const [driftDisplay, setDriftDisplay] = useState(reduced ? drift : 0);
  useEffect(() => {
    if (reduced) {
      setDriftDisplay(drift);
      return;
    }
    setDriftDisplay(0);
    const t0 = performance.now();
    let raf = 0;
    const step = (t: number) => {
      const p = Math.min((t - t0) / 700, 1);
      setDriftDisplay(Math.round(drift * p));
      if (p < 1) raf = requestAnimationFrame(step);
    };
    raf = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf);
  }, [drift, reduced, focusKey, win, detailOpen]);

  const W = Math.max(640, width);
  const H = height;
  const pW = W - PAD.L - PAD.R;
  const pTop = PAD.T;
  const pBot = H - PAD.B;
  const DX = (i: number) => PAD.L + (i / (slots - 1)) * pW;
  const DY = (v: number) => pTop + ((Y_MAX - v) / (Y_MAX - Y_MIN)) * (pBot - pTop);

  // Projection (next 2 months from slope)
  const last = fv[n - 1];
  const slope = (fv[n - 1] - fv[n - 3]) / 2;
  const p1 = last + slope;
  const p2 = last + 2 * slope;

  // Find CM1 breach point along projection
  let breach: { x: number; weeks: number } | null = null;
  const seg = [
    [n - 1, last],
    [n, p1],
    [n + 1, p2],
  ];
  for (let i = 0; i < seg.length - 1; i++) {
    const [xa, ya] = seg[i];
    const [xb, yb] = seg[i + 1];
    if (ya < THREAT_INDEX && yb >= THREAT_INDEX) {
      const t = (THREAT_INDEX - ya) / (yb - ya);
      const sc = xa + (xb - xa) * t;
      breach = { x: DX(sc), weeks: Math.round((sc - (n - 1)) * 4.33) };
      break;
    }
  }

  // Hover crosshair
  const handleHover = (e: React.MouseEvent<SVGRectElement>) => {
    const svg = e.currentTarget.ownerSVGElement;
    if (!svg) return;
    const r = svg.getBoundingClientRect();
    const sc = r.width / W;
    const mvx = (e.clientX - r.left) / sc;
    let i = Math.round(((mvx - PAD.L) / pW) * (slots - 1));
    i = Math.max(0, Math.min(n - 1, i));
    setHover({ i, v: fv[i], m: months[i], x: DX(i), y: DY(fv[i]) });
  };

  const cornerLen = 14;
  const corner = (x: number, y: number, dx: number, dy: number) => (
    <path
      className="brk"
      d={`M${x + dx * cornerLen},${y} L${x},${y} L${x},${y + dy * cornerLen}`}
    />
  );

  return (
    <>
      <div className="drift-readout">
        <div className="big">
          {driftDisplay >= 0 ? "+" : ""}
          {driftDisplay}%
        </div>
        <div className="d">
          {focus.name} · {focus.type} · last {win} mo
        </div>
        <div className="sub">
          {focus.comp}
          {focus.key === "shenzhen" ? " — the drift is logistics, not product" : ""}
        </div>
      </div>

      <div className="chart-main-inner" ref={ref}>
        <svg id="drift" viewBox={`0 0 ${W} ${H}`}>
          {/* Gridlines + Y labels */}
          {[100, 108].map((v) => (
            <g key={v}>
              <line className="grid" x1={PAD.L} y1={DY(v)} x2={W - PAD.R} y2={DY(v)} />
              <text className="ylab" x={PAD.L + 3} y={DY(v) - 5}>
                {v}
              </text>
            </g>
          ))}

          {/* Threat line */}
          <line className="threat" x1={PAD.L} y1={DY(THREAT_INDEX)} x2={W - PAD.R} y2={DY(THREAT_INDEX)} />
          <text className="threatlab" x={W - PAD.R - 3} y={DY(THREAT_INDEX) - 5} textAnchor="end">
            CM1 target ceiling · {THREAT_INDEX}
          </text>

          {/* Baseline */}
          <line className="base" x1={PAD.L} y1={pBot} x2={W - PAD.R} y2={pBot} />

          {/* Tick marks */}
          {Array.from({ length: n }).map((_, i) => (
            <g key={`tk-${i}`}>
              <line className="tk" x1={DX(i)} y1={pBot} x2={DX(i)} y2={pBot - 8} opacity={0.3} />
              {i < n - 1 && (
                <line
                  className="tk"
                  x1={DX(i + 0.5)}
                  y1={pBot}
                  x2={DX(i + 0.5)}
                  y2={pBot - 5}
                  opacity={0.18}
                />
              )}
            </g>
          ))}

          {/* X labels */}
          {months.map((m, i) => (
            <text
              key={m + i}
              className={`xlab${i === n - 1 ? " now" : ""}`}
              x={DX(i)}
              y={pBot + 18}
              textAnchor="middle"
            >
              {m}
            </text>
          ))}

          {/* Freight event marker (shenzhen) */}
          {focus.key === "shenzhen" && n >= 5 && (
            <>
              <line className="evt" x1={DX(n - 4)} y1={pTop} x2={DX(n - 4)} y2={pBot} />
              <text className="evtlab" x={DX(n - 4) + 5} y={pTop + 10}>
                freight ↑
              </text>
            </>
          )}

          {/* Other suppliers (greyed) */}
          {SUP_SERIES.filter((s: SupSeries) => s.key !== focus.key).map((s) => {
            const sv = s.v.slice(off);
            const pts = sv.map((v, i) => `${DX(i)},${DY(v)}`).join(" ");
            return (
              <polyline
                key={s.key}
                className="ln"
                points={pts}
                stroke={s.col}
                strokeWidth={1.4}
                opacity={0.3}
              />
            );
          })}

          {/* Focus line */}
          <polyline
            className="ln draw"
            points={fv.map((v, i) => `${DX(i)},${DY(v)}`).join(" ")}
            stroke={focus.col}
            strokeWidth={2.4}
          />

          {/* Projection */}
          <polyline
            className="proj"
            points={`${DX(n - 1)},${DY(last)} ${DX(n)},${DY(p1)} ${DX(n + 1)},${DY(p2)}`}
            stroke={focus.col}
            strokeWidth={2}
            opacity={0.8}
          />

          {/* Breach indicator */}
          {breach && (
            <>
              <line
                x1={breach.x}
                y1={DY(THREAT_INDEX)}
                x2={breach.x}
                y2={pBot}
                stroke="var(--loss)"
                strokeWidth={1}
                strokeDasharray="2 3"
                opacity={0.55}
              />
              <circle className="breach" cx={breach.x} cy={DY(THREAT_INDEX)} r={4.5} />
              <text className="breachlab" x={breach.x} y={pBot + 18} textAnchor="middle">
                ~{breach.weeks} wks
              </text>
            </>
          )}

          {/* Square nodes */}
          {fv.map((v, i) => {
            const isLast = i === n - 1;
            return (
              <rect
                key={`nd-${i}`}
                className="node pop"
                x={DX(i) - 3.5}
                y={DY(v) - 3.5}
                width={7}
                height={7}
                rx={1.5}
                fill={isLast ? focus.col : "#fff"}
                stroke={focus.col}
                style={reduced ? undefined : { animationDelay: `${0.5 + i * 0.04}s` }}
              />
            );
          })}

          {/* Drop line + pulsing beacon at latest */}
          <line className="drop" x1={DX(n - 1)} y1={DY(last)} x2={DX(n - 1)} y2={pBot} />
          {!reduced && (
            <>
              <circle cx={DX(n - 1)} cy={DY(last)} r={5} fill="none" stroke="var(--compass)" strokeWidth={1.4}>
                <animate attributeName="r" values="5;20" dur="2.2s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.55;0" dur="2.2s" repeatCount="indefinite" />
              </circle>
              <circle cx={DX(n - 1)} cy={DY(last)} r={5} fill="none" stroke="var(--compass)" strokeWidth={1.4}>
                <animate attributeName="r" values="5;20" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.55;0" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
              </circle>
            </>
          )}

          {/* Readout window above latest point */}
          {(() => {
            const ww = 82;
            const wh = 28;
            const wx = DX(n - 1) - ww / 2;
            const wy = DY(last) - wh - 12;
            return (
              <g>
                <line
                  className="drop"
                  x1={DX(n - 1)}
                  y1={wy + wh}
                  x2={DX(n - 1)}
                  y2={DY(last)}
                  opacity={0.45}
                />
                <rect className="rwin" x={wx} y={wy} width={ww} height={wh} rx={5} />
                <rect className="rtick" x={wx} y={wy + 5} width={3} height={wh - 10} rx={1.5} />
                <text className="rwin-v" x={wx + 12} y={wy + 15}>
                  {last}
                </text>
                <text className="rwin-l" x={wx + 12} y={wy + 24}>
                  INDEX · {drift >= 0 ? "+" : ""}
                  {drift}%
                </text>
              </g>
            );
          })()}

          {/* Corner brackets */}
          {corner(PAD.L, pTop, 1, 1)}
          {corner(W - PAD.R, pTop, -1, 1)}
          {corner(PAD.L, pBot, 1, -1)}
          {corner(W - PAD.R, pBot, -1, -1)}

          {/* Crosshair on hover */}
          {hover && (
            <line
              className="xhair"
              x1={hover.x}
              y1={pTop}
              x2={hover.x}
              y2={pBot}
              style={{ opacity: 0.7 }}
            />
          )}

          {/* Hover capture */}
          <rect
            x={PAD.L}
            y={pTop}
            width={pW}
            height={pBot - pTop}
            fill="transparent"
            onMouseMove={handleHover}
            onMouseLeave={() => setHover(null)}
          />
        </svg>

        {/* Tooltip */}
        {hover && (
          <div
            className="dtip"
            style={{
              display: "block",
              left: `${(hover.x / W) * 100}%`,
              top: `${(hover.y / H) * 100}%`,
            }}
          >
            <div className="tv">{hover.v}</div>
            <div className="td">{hover.m} · index</div>
          </div>
        )}
      </div>
    </>
  );
}
