/**
 * Mock data for the Operations · Suppliers sub-page.
 *
 * Two parallel arrays:
 *   - SUP_SERIES    — 12-month landed-cost INDEX (base 100) per supplier
 *                     used by the drift chart
 *   - SUPPLIERS     — supplier rollup for the ledger
 *
 * Plus CAPITAL_DRAG (deposit cash frozen during manufacturing).
 */

export type SupplierType = "import" | "local" | "OEM";
export type SupplierVerdict = "negotiate" | "reorder" | "diversify" | "hold";
export type SupplierStatus = "drift" | "reorder" | "stable" | "sole";

export interface SupSeries {
  key: string;
  name: string;
  type: SupplierType;
  col: string;
  v: number[];
  comp: string;
}

export interface SupplierRow {
  key: string;
  name: string;
  type: SupplierType;
  items: number;
  risk: number;
  /** Lead time in days */
  lead: number;
  /** On-time delivery % */
  otd: number;
  last: string;
  /** USD spend over 90 days */
  spend: number;
  status: SupplierStatus;
  statusLabel: string;
  verdict: SupplierVerdict;
}

export interface CapitalDragRow {
  key: string;
  name: string;
  type: SupplierType;
  days: number;
  /** USD frozen */
  frozen: number;
}

