"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { DriftChart } from "@/features/ops/components/DriftChart";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  SUP_SERIES,
  SUPPLIERS,
  CAPITAL_DRAG,
  suppliersAI,
  suppliersConsole,
  type SupplierRow,
  type SupplierVerdict,
} from "@/features/ops/api/ops-suppliers-data";
import "./suppliers.css";

const fmtUSD = (v: number) => {
  if (v >= 1_000_000) return `$${(v / 1_000_000).toFixed(2).replace(/\.?0+$/, "")}M`;
  if (v >= 1000) return `$${Math.round(v / 1000)}K`;
  return `$${Math.round(v)}`;
};

const TYPE_ICON: Record<string, React.ReactNode> = {
  import: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 9l9-5 9 5v8l-9 5-9-5z" />
      <path d="M3 9l9 5 9-5M12 14v8" />
    </svg>
  ),
  local: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 11l8-6 8 6" />
      <path d="M6.5 10v9h11v-9" />
    </svg>
  ),
  OEM: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="3" />
      <path d="M12 2v3M12 19v3M2 12h3M19 12h3M5 5l2 2M17 17l2 2M19 5l-2 2M7 17l-2 2" />
    </svg>
  ),
};

type SortKey = "n" | "items" | "risk" | "lead" | "otd" | "spend";

const PERIODS = ["3 months", "6 months", "12 months"];
const PERIOD_WIN = [3, 6, 12];

const VERDICT_LABEL: Record<SupplierVerdict, string> = {
  negotiate: "Negotiate",
  reorder: "Reorder",
  diversify: "Diversify",
  hold: "Hold",
};
const VERDICT_STRIPE: Record<SupplierVerdict, string> = {
  negotiate: "#b88a2a",
  reorder: "#1D9E75",
  diversify: "#D85A30",
  hold: "transparent",
};

function reasonForSupplier(s: SupplierRow, drift: number): string {
  if (s.verdict === "negotiate")
    return `Landed cost drifting +${drift}% on freight — the base price never moved. Open a forwarder renegotiation before CM1 breaches.`;
  if (s.verdict === "reorder")
    return `${s.risk} items sitting on thin cover. Place the reorder before the category gaps.`;
  if (s.verdict === "diversify")
    return `Sole-sources its ${s.items} items — one delay stops the whole category. Add a second source to break the dependency.`;
  return `Stable — cost and lead time within range, on-time at ${s.otd}%. Nothing to act on.`;
}

export default function SuppliersPage() {
  const [periodIdx, setPeriodIdx] = useState(2); // default 12 months
  const win = PERIOD_WIN[periodIdx];
  const [selectedKey, setSelectedKey] = useState<string | null>(null);
  const [verdictFilter, setVerdictFilter] = useState<"all" | SupplierVerdict>("all");
  const [search, setSearch] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>("spend");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [rowBridgeSent, setRowBridgeSent] = useState<string | null>(null);
  const [detailBridgeSent, setDetailBridgeSent] = useState(false);

  const focusKey = selectedKey ?? "shenzhen";
  const focusSeries = SUP_SERIES.find((s) => s.key === focusKey) ?? SUP_SERIES[0];

  // Spend-weighted legend tiers
  const totalSpend = useMemo(
    () => SUPPLIERS.reduce((a, s) => a + s.spend, 0),
    [],
  );
  const tieredLegend = useMemo(() => {
    return SUP_SERIES
      .map((s) => {
        const row = SUPPLIERS.find((r) => r.key === s.key);
        const spend = row?.spend ?? 0;
        return {
          ...s,
          spend,
          tier: (spend / totalSpend) >= 0.15 ? ("tier1" as const) : ("minor" as const),
        };
      })
      .sort((a, b) => b.spend - a.spend);
  }, [totalSpend]);

  const totalFrozen = CAPITAL_DRAG.reduce((a, d) => a + d.frozen, 0);
  const maxFrozen = Math.max(...CAPITAL_DRAG.map((d) => d.frozen));
  const dragSorted = [...CAPITAL_DRAG].sort((a, b) => b.frozen - a.frozen);

  // Filter + sort ledger
  const rows = useMemo(() => {
    const filtered = SUPPLIERS.filter((s) => {
      if (verdictFilter !== "all" && s.verdict !== verdictFilter) return false;
      if (search) {
        const q = search.toLowerCase();
        if (!(s.name.toLowerCase().includes(q) || s.type.toLowerCase().includes(q))) return false;
      }
      return true;
    });
    return filtered.sort((a, b) => {
      if (sortKey === "n") return a.name.localeCompare(b.name) * sortDir;
      const av = (a[sortKey] as unknown as number) ?? 0;
      const bv = (b[sortKey] as unknown as number) ?? 0;
      return (av - bv) * sortDir;
    });
  }, [verdictFilter, search, sortKey, sortDir]);

  const selected = selectedKey ? SUPPLIERS.find((s) => s.key === selectedKey) ?? null : null;
  const selectedSeries = selected ? SUP_SERIES.find((s) => s.key === selected.key) : null;
  const selectedDrift = selectedSeries
    ? selectedSeries.v[selectedSeries.v.length - 1] - selectedSeries.v[0]
    : 0;

  const onSelect = (key: string) => {
    setSelectedKey((cur) => (cur === key ? null : key));
    setDetailBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "n" ? 1 : -1);
    }
  };
  const { openBridge } = useBridge();
  /** Per execution map §05 Suppliers: each verdict → its Bridge flow. */
  const supplierVerdictToPage: Record<SupplierVerdict, BridgePage> = {
    negotiate: "adjust-supplier",
    reorder: "reorder",
    diversify: "diversify-supplier",
    hold: "hold",
  };
  const sendRowBridge = (key: string, verdict: SupplierVerdict) => {
    setRowBridgeSent(key);
    openBridge("ops", supplierVerdictToPage[verdict]);
    setTimeout(() => setRowBridgeSent(null), 1500);
  };
  const sendDetailBridge = (verdict: SupplierVerdict) => {
    setDetailBridgeSent(true);
    openBridge("ops", supplierVerdictToPage[verdict]);
    setTimeout(() => setDetailBridgeSent(false), 1800);
  };

  const driftArg = (() => {
    // Project breach for shenzhen-like trajectories
    const slope = (focusSeries.v[focusSeries.v.length - 1] - focusSeries.v[focusSeries.v.length - 3]) / 2;
    const last = focusSeries.v[focusSeries.v.length - 1];
    const willBreach = slope > 0 && last + slope * 4 >= 116;
    if (willBreach) {
      const weeks = Math.round(((116 - last) / slope) * 4.33);
      return `At the current slope, <b class="red">CM1 on Screen Protector breaches target in ~${weeks} weeks</b> — silently, because the base price never moved. This is the cost invoice-watching misses: freight and duty creep, not the number on the PO.`;
    }
    return `<b class="grn">No margin threat here</b> — landed cost has held within a couple of points across the window. The drift to watch is concentrated in one import source, not the whole base.`;
  })();

  const SCOLS: Array<{ k: SortKey | "last" | "status" | "verdict"; l: string; sort: boolean; num?: boolean }> = [
    { k: "n", l: "Supplier", sort: true },
    { k: "items", l: "Items", sort: true, num: true },
    { k: "risk", l: "At risk", sort: true, num: true },
    { k: "lead", l: "Lead", sort: true, num: true },
    { k: "otd", l: "On-time", sort: true, num: true },
    { k: "last", l: "Last order", sort: false, num: true },
    { k: "spend", l: "Spend 90d", sort: true, num: true },
    { k: "status", l: "Status", sort: false, num: true },
    { k: "verdict", l: "Verdict", sort: false, num: true },
  ];

  const otdClass = (otd: number) => (otd < 90 ? "lo" : otd < 95 ? "mid" : "");

  return (
    <div className="ops-suppliers-page">
      <DeptHeader
        dept="ops"
        title="Suppliers"
        meta={<><span className="live">Live</span> · 5 suppliers · Updated 2 min ago</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="add-supplier">Add supplier</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIODS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* ───── Drift chart card ───── */}
      <section className="chart-card">
        <div className="c-head">
          <div>
            <div className="c-k">Landed cost drift · monthly index</div>
            <div className="drift-readout">
              {/* big + meta rendered inside DriftChart for animation */}
            </div>
          </div>
          <div className="cluster">
            <div className="chart-legend">
              {tieredLegend.map((s) => (
                <button
                  key={s.key}
                  className={`dlg ${s.tier}${s.key === selectedKey ? " sel" : ""}`}
                  onClick={() => onSelect(s.key)}
                  type="button"
                >
                  <span className="sw" style={{ background: s.col }} />
                  <span className="nm">{s.name}</span>
                  {s.tier === "tier1" && <span className="ty">{s.type}</span>}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className={`chart-split${selectedKey ? " open" : ""}`}>
          <div className="chart-main">
            <DriftChart focusKey={focusKey} win={win} detailOpen={!!selectedKey} />
          </div>

          <aside className="chart-detail">
            {!selected ? (
              <div className="sd-empty">
                <div className="ttl">Inspect a supplier</div>
                <div className="lead">
                  Click any supplier — in the chart legend or the ledger below — to inspect its cost drift, lead time and concentration, and send its verdict to Bridge.
                </div>
                <div className="snap">
                  <div className="sd-snap-row">
                    <span className="l">Suppliers</span>
                    <span className="v">5</span>
                  </div>
                  <div className="sd-snap-row">
                    <span className="l">Spend · 90d</span>
                    <span className="v">$1.01M</span>
                  </div>
                  <div className="sd-snap-row">
                    <span className="l">Top-2 concentration</span>
                    <span className="v" style={{ color: "#b3502e" }}>65%</span>
                  </div>
                </div>
              </div>
            ) : (
              <>
                <div className="sd-head">
                  <div>
                    <div className="sd-name">{selected.name}</div>
                    <div className="sd-sku">{selected.type} · last order {selected.last}</div>
                  </div>
                  <button className="sd-clear" onClick={() => setSelectedKey(null)}>
                    clear ✕
                  </button>
                </div>
                <div className="sd-grid">
                  <div className="sd-cell">
                    <div className="l">Items</div>
                    <div className="v">{selected.items}</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">At-risk</div>
                    <div className={`v ${selected.risk > 0 ? "red" : ""}`}>
                      {selected.risk > 0 ? selected.risk : "—"}
                    </div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Lead time</div>
                    <div className="v">{selected.lead}d</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">On-time</div>
                    <div className={`v ${selected.otd < 90 ? "red" : selected.otd < 95 ? "ops" : "grn"}`}>
                      {selected.otd}%
                    </div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Spend 90d</div>
                    <div className="v">{fmtUSD(selected.spend)}</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Cost drift</div>
                    <div className={`v ${selectedDrift >= 8 ? "red" : selectedDrift >= 3 ? "ops" : ""}`}>
                      {selectedDrift > 0 ? "+" : ""}{selectedDrift}%
                    </div>
                  </div>
                </div>
                <div className="sd-verdict">
                  <div className="sd-vrow">
                    <span
                      className="vp"
                      style={{
                        color: {
                          negotiate: "#9a6a18",
                          reorder: "#157a5b",
                          diversify: "#b3502e",
                          hold: "var(--ink-2)",
                        }[selected.verdict],
                        background: {
                          negotiate: "rgba(184,138,42,0.16)",
                          reorder: "rgba(29,158,117,0.13)",
                          diversify: "rgba(216,90,48,0.13)",
                          hold: "rgba(0,0,0,0.05)",
                        }[selected.verdict],
                      }}
                    >
                      {selected.verdict}
                    </span>
                    <span className="cl">{selected.statusLabel}</span>
                  </div>
                  <div className="sd-reason">{reasonForSupplier(selected, selectedDrift)}</div>
                  <button
                    className={`sd-bridge${detailBridgeSent ? " sent" : ""}`}
                    onClick={() => sendDetailBridge(selected.verdict)}
                  >
                    {detailBridgeSent
                      ? `${selected.verdict} sent to Bridge ✓`
                      : `${selected.verdict} → Bridge`}
                  </button>
                </div>
              </>
            )}
          </aside>
        </div>

        <div className="cap-arg">
          <span className="mk" />
          <p dangerouslySetInnerHTML={{ __html: driftArg }} />
        </div>
      </section>

      {/* ───── Metric strip ───── */}
      <div className="metric-strip">
        {[
          { l: "Suppliers", v: SUPPLIERS.length, s: "active sources" },
          { l: "Items supplied", v: SUPPLIERS.reduce((a, s) => a + s.items, 0), s: "across catalog" },
          { l: "Items at risk", v: SUPPLIERS.reduce((a, s) => a + s.risk, 0), s: "2 suppliers", cls: "red" },
          { l: "Spend · 90 days", v: fmtUSD(totalSpend), s: "landed COGS" },
          { l: "Top-2 concentration", v: "65%", s: "diversification risk", cls: "ops" },
        ].map((c, i) => (
          <div key={i} className="metric">
            <div className="metric-l">{c.l}</div>
            <div className={`metric-v ${c.cls || ""}`}>{c.v}</div>
            <div className="metric-s">{c.s}</div>
          </div>
        ))}
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={suppliersAI.label} meta={suppliersAI.meta} cards={suppliersAI.cards} />

      {/* ───── Supplier ledger ───── */}
      <SectionLabel>Supplier ledger — reliability &amp; spend</SectionLabel>
      <div className="ldg-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search supplier or type…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="filters">
          {(["all", "negotiate", "reorder", "diversify", "hold"] as const).map((v) => (
            <button
              key={v}
              className={`fchip${verdictFilter === v ? " active" : ""}`}
              onClick={() => setVerdictFilter(v)}
            >
              {v === "all" ? "All" : v.charAt(0).toUpperCase() + v.slice(1)}
            </button>
          ))}
        </div>
      </div>

      <div className="ledger">
        <div className="ldg-head">
          {SCOLS.map((c, i) => {
            const active = c.sort && sortKey === c.k;
            return (
              <div
                key={i}
                className={`th${c.num ? " num" : ""}${active ? " active" : ""}`}
                onClick={() => {
                  if (c.sort) handleSort(c.k as SortKey);
                }}
                style={c.sort ? undefined : { cursor: "default" }}
              >
                {c.l}
                {c.sort && (
                  <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                )}
              </div>
            );
          })}
        </div>

        {rows.length === 0 ? (
          <div className="ldg-empty">No suppliers match this filter</div>
        ) : (
          rows.map((s) => (
            <div
              key={s.key}
              className={`ldg-row${selectedKey === s.key ? " sel" : ""}`}
              style={{ ["--vstripe" as string]: VERDICT_STRIPE[s.verdict] } as React.CSSProperties}
              onClick={() => onSelect(s.key)}
            >
              <div className="sup-wrap">
                <div className="sup-ic">{TYPE_ICON[s.type]}</div>
                <div className="sup-meta">
                  <div className="nm">{s.name}</div>
                  <div className="ty">{s.type}</div>
                </div>
              </div>
              <div className="sup-n">{s.items}</div>
              <div className={`sup-n ${s.risk > 0 ? "alarm" : "muted"}`}>
                {s.risk > 0 ? s.risk : "—"}
              </div>
              <div className="sup-n">{s.lead}d</div>
              <div className={`sup-otd ${otdClass(s.otd)}`}>{s.otd}%</div>
              <div className="sup-sub">{s.last}</div>
              <div className="sup-n anchor">{fmtUSD(s.spend)}</div>
              <div className="inv-status">
                <span className={`spill ${s.status}`}>{s.statusLabel}</span>
              </div>
              <div className="ldg-verdict">
                <span className={`vpill ${s.verdict}`}>{s.verdict}</span>
              </div>
              <button
                className={`ldg-bridge${rowBridgeSent === s.key ? " sent" : ""}`}
                onClick={(e) => {
                  e.stopPropagation();
                  sendRowBridge(s.key, s.verdict);
                }}
              >
                {rowBridgeSent === s.key ? `${VERDICT_LABEL[s.verdict]} sent ✓` : (
                  <>
                    {VERDICT_LABEL[s.verdict]}
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <line x1="5" y1="12" x2="19" y2="12" />
                      <polyline points="12 5 19 12 12 19" />
                    </svg>
                  </>
                )}
              </button>
            </div>
          ))
        )}
      </div>

      {/* ───── Capital drag card ───── */}
      <SectionLabel>Lead-time capital drag — deposit frozen during manufacturing</SectionLabel>
      <section className="drag-card">
        <div className="c-head">
          <div>
            <div className="c-k">Deposit cash locked before goods can be sold</div>
            <div className="c-hero">
              <span className="big">{fmtUSD(totalFrozen)}</span>
              <span className="d">frozen across 4 suppliers</span>
            </div>
            <div className="c-sub">
              deposit paid → manufacturing → delivery → first sellable day
            </div>
          </div>
          <div className="cluster">
            <div className="verified">
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="var(--compass)" strokeWidth="2">
                <circle cx="12" cy="12" r="9" />
                <path d="M12 7v5l3 2" />
              </svg>
              <div className="vt">
                <b>Capital, not just price</b>
                <span>a cheaper unit with a longer freeze can cost more</span>
              </div>
            </div>
          </div>
        </div>

        <div className="drag-list">
          {dragSorted.map((d) => {
            const isZero = d.frozen === 0;
            const w = isZero ? 0 : Math.max((d.frozen / maxFrozen) * 100, 14);
            const fillBg = {
              import: "linear-gradient(180deg,#e3744a,#D85A30)",
              OEM: "linear-gradient(180deg,#c79a3e,#b88a2a)",
              local: "none",
            }[d.type];
            return (
              <div key={d.key} className="drag-row">
                <div className="drag-sup">
                  <span className="drag-name">{d.name}</span>
                  <span className="drag-type">{d.type}</span>
                </div>
                <div className="drag-track">
                  {isZero ? (
                    <div className="drag-fill zero">
                      <span className="amt">$0 · net-30 terms</span>
                    </div>
                  ) : (
                    <div className="drag-fill" style={{ width: `${w}%`, background: fillBg }}>
                      <span className="amt">{fmtUSD(d.frozen)}</span>
                    </div>
                  )}
                </div>
                <div className="drag-days">
                  <div className="dv">{d.days}d</div>
                  <div className="dl">freeze</div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="cap-arg">
          <span className="mk" style={{ background: "var(--compass)" }} />
          <p>
            <b>Shenzhen freezes the most cash</b> — $165K locked for 24 days — while <b>Chiang Mai freezes it longest</b> at 30. Bangkok&rsquo;s net-30 terms freeze nothing: a structural advantage worth leaning on when two suppliers can ship the same thing.
          </p>
        </div>
      </section>

      {/* ───── Console note ───── */}
      <section className="console">
        <div className="console-label">
          <span style={{ width: 18, height: 18, borderRadius: 4, background: "var(--cream)", color: "var(--navy-deep)", display: "inline-flex", alignItems: "center", justifyContent: "center", fontFamily: "Inter", fontSize: 11, fontWeight: 600 }}>
            M
          </span>
          Console note
        </div>
        <div className="console-row">
          <div className="console-tag read">Read</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: suppliersConsole.read }} />
        </div>
        <div className="console-row">
          <div className="console-tag exposure">Exposure</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: suppliersConsole.exposure }} />
        </div>
        <div className="console-row">
          <div className="console-tag directive">Directive</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: suppliersConsole.directive }} />
        </div>
      </section>

    </div>
  );
}
